#include<bits/stdc++.h>
using namespace std;
vector<pair<int,int>> mp[500010];
int n,s;
long long dis[500010],ans;
void dfs(int x,int fa=-1)
{
    for(auto i:mp[x])
    {
        int v=i.first,val=i.second;
        if(v!=fa)
        {
            dfs(v,x);
            dis[x]=max(dis[x],dis[v]+val);
        }
    }
    for(auto i:mp[x])
    {
        int v=i.first,val=i.second;
        if(v!=fa)
        {
            ans+=dis[x]-(dis[v]+val);
        }
    }
}
int main()
{
    int n,s;
    scanf("%d%d",&n,&s);
    for(int i=1;i<n;i++)
    {
        int u,v,w;
        scanf("%d%d%d",&u,&v,&w);
        mp[u].push_back(make_pair(v,w));
        mp[v].push_back(make_pair(u,w));
    }
    dfs(s);
    printf("%lld",ans);
    return 0;
}
